48	pub struct Avm2ButtonData<'gc> {
49	    base: InteractiveObjectBase<'gc>,
50	
51	    shared: Gc<'gc, ButtonShared>,
52	
53	    /// The display object tree to render when the button is in the UP state.
54	    up_state: Lock<Option<DisplayObject<'gc>>>,
55	
56	    /// The display object tree to render when the button is in the OVER state.
57	    over_state: Lock<Option<DisplayObject<'gc>>>,
58	
59	    /// The display object tree to render when the button is in the DOWN state.
60	    down_state: Lock<Option<DisplayObject<'gc>>>,
61	
62	    /// The display object tree to use for mouse hit checks.
63	    hit_area: Lock<Option<DisplayObject<'gc>>>,
64	
65	    /// The class of this button.
66	    ///
67	    /// If not specified in `SymbolClass`, this will be
68	    /// `flash.display.SimpleButton`.
69	    class: Lock<Avm2ClassObject<'gc>>,
70	
71	    /// The AVM2 representation of this button.
72	    object: Lock<Option<Avm2StageObject<'gc>>>,
73	
74	    /// The current button state to render.
75	    state: Cell<ButtonState>,
76	
77	    /// The current tracking mode of this button.
78	    tracking: Cell<ButtonTracking>,
79	
80	    enabled: Cell<bool>,
81	    use_hand_cursor: Cell<bool>,
82	
83	    /// If this button needs to have it's child states constructed, or not.
84	    ///
85	    /// All buttons start out unconstructed and have this flag set `true`.
86	    /// This flag is consumed during frame construction.
87	    needs_frame_construction: Cell<bool>,
88	
89	    /// Skip the next `run_frame` call.
90	    ///
91	    /// This flag exists due to a really odd feature of buttons: they run their
92	    /// children for one frame before parents can run. Then they go back to the
93	    /// normal AVM2 execution order for future frames.
94	    skip_current_frame: Cell<bool>,
95	
96	    /// When we initially construct a button and run a nested frame,
97	    /// we run the framescripts for our states in a different order then
98	    /// we do for all other framescript runs.
99	    weird_framescript_order: Cell<bool>,
100	}
