325	    fn render_self(self, context: &mut RenderContext<'_, 'gc>) {
326	        self.render_children(context);
327	    }
328	
329	    fn self_bounds(self, _mode: BoundsMode) -> Rectangle<Twips> {
330	        // No inherent bounds; contains child DisplayObjects.
331	        Default::default()
332	    }
