334	    fn hit_test_shape(
335	        self,
336	        context: &mut UpdateContext<'gc>,
337	        point: Point<Twips>,
338	        options: HitTestOptions,
339	    ) -> bool {
340	        for child in self.iter_render_list() {
341	            if child.hit_test_shape(context, point, options) {
342	                return true;
343	            }
344	        }
345	
346	        false
347	    }
