363	        for child in self.iter_render_list() {
364	            child.avm1_unload(context);
365	        }
366	
367	        self.drop_focus(context);
368	
369	        if let Some(node) = self.maskee() {
370	            node.set_masker(context.gc(), None, true);
371	        } else if let Some(node) = self.masker() {
372	            node.set_maskee(context.gc(), None, true);
373	        }
374	
375	        // Do *not* unregister text field bindings.
376	
377	        self.set_avm1_removed(true);
378	    }
