380	    fn avm1_text_field_bindings(&self) -> Option<Ref<'_, [Avm1TextFieldBinding<'gc>]>> {
381	        let read = Gc::as_ref(self.0).cell.borrow();
382	        Some(Ref::map(read, |r| &*r.text_field_bindings))
383	    }
