386	        &self,
387	        mc: &Mutation<'gc>,
388	    ) -> Option<RefMut<'_, Vec<Avm1TextFieldBinding<'gc>>>> {
389	        let write = unlock!(Gc::write(mc, self.0), Avm1ButtonData, cell).borrow_mut();
