664	struct ButtonSharedMut {
665	    records: Vec<swf::ButtonRecord>,
666	
667	    /// The sounds to play on state changes for this button.
668	    up_to_over_sound: Option<swf::ButtonSound>,
669	    over_to_down_sound: Option<swf::ButtonSound>,
