1	//! Frame events management
2	//!
3	//! This module aids in keeping track of which frame execution phase we are in.
4	//!
5	//! For AVM2 code, display objects execute a series of discrete phases, and
6	//! each object is notified about the current frame phase in rendering order.
7	//! When objects are created, they are 'caught up' to the current frame phase
8	//! to ensure correct order of operations.
9	//!
10	//! AVM1 code (presumably, either on an AVM1 stage or within an `AVM1Movie`)
11	//! runs in one phase, with timeline operations executing with all phases
12	//! inline in the order that clips were originally created.
13	
14	use crate::avm2::{Avm2, EventObject};
15	use crate::context::UpdateContext;
16	use crate::display_object::{DisplayObject, MovieClip, TDisplayObject};
17	use crate::loader::LoadManager;
18	use crate::orphan_manager::OrphanManager;
19	use tracing::instrument;
20	
21	/// Which phase of the frame we're currently in.
22	///
23	/// AVM2 frames exist in one of four phases: `Enter`, `Construct`,
24	/// `FrameScripts`, or `Exit`. An additional `Idle` phase covers rendering and
25	/// event processing.
26	#[derive(Copy, Clone, PartialEq, Eq, Debug, Default)]
27	pub enum FramePhase {
28	    /// We're entering the next frame.
29	    ///
30	    /// When movie clips enter a new frame, they must do two things:
31	    ///
32	    ///  - Remove all children that should not exist on the next frame.
33	    ///  - Increment their current frame number.
34	    ///
35	    /// Once this phase ends, we fire `enterFrame` on the broadcast list.
36	    Enter,
37	
38	    /// We're constructing children of existing display objects.
39	    ///
40	    /// All `PlaceObject` tags should execute at this time.
41	    ///
42	    /// Once we construct the frame, we fire `frameConstructed` on the
43	    /// broadcast list.
44	    Construct,
45	
46	    /// We're running all queued frame scripts.
47	    ///
48	    /// Frame scripts are the AS3 equivalent of old-style `DoAction` tags. They
49	    /// are queued in the `Update` phase if the current timeline frame number
50	    /// differs from the prior frame's one.
51	    FrameScripts,
52	
53	    /// We're finishing frame processing.
54	    ///
55	    /// When we exit a completed frame, we fire `exitFrame` on the broadcast
56	    /// list.
57	    Exit,
58	
59	    /// We're not currently executing any frame code.
60	    ///
61	    /// At this point in time, event handlers are expected to run. No frame
62	    /// catch-up work should execute.
63	    #[default]
64	    Idle,
65	}
66	
67	/// Run one frame according to AVM2 frame order.
68	/// NOTE: The `each_orphan_movie` calls are in really odd places,
69	/// but this is needed to match Flash Player's output. There may
70	/// still be lurking bugs, but the current code matches Flash's
71	/// output exactly for two complex test cases (see `avm2/orphan_movie*`)
72	#[instrument(level = "debug", skip_all)]
73	pub fn run_all_phases_avm2(context: &mut UpdateContext<'_>) {
74	    let stage = context.stage;
75	
76	    if !stage.movie().is_action_script_3() {
77	        return;
78	    }
79	
80	    *context.frame_phase = FramePhase::Enter;
81	    OrphanManager::each_orphan_obj(context, |orphan, context| {
82	        orphan.enter_frame(context);
83	    });
84	    stage.enter_frame(context);
85	
86	    *context.frame_phase = FramePhase::Construct;
87	    OrphanManager::each_orphan_obj(context, |orphan, context| {
88	        orphan.construct_frame(context);
89	    });
90	    stage.construct_frame(context);
91	    broadcast_frame_constructed(context);
92	
93	    *context.frame_phase = FramePhase::FrameScripts;
94	    OrphanManager::each_orphan_obj(context, |orphan, context| {
95	        orphan.run_frame_scripts(context);
96	    });
97	    stage.run_frame_scripts(context);
98	    run_frame_script_cleanup(context);
99	
100	    *context.frame_phase = FramePhase::Exit;
101	    broadcast_frame_exited(context);
102	
103	    // We cannot easily remove dead `GcWeak` instances from the orphan list
104	    // inside `each_orphan_movie`, since the callback may modify the orphan list.
